    (1054, 'My parents have always supported me.', 'phrase', '779329983fd642dedf3537cf0b7de3507fb0771f35f3c94d20f76e8e2b80f6b2', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_004", "note_culturale": null}', NULL),
