    (1063, 'My mother-in-law is a fantastic person!', 'phrase', '21d7144e3a7f2b13bc672933a04d03e0809dd75b16b68eb753705a3b01d04ec1', 'A1', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_007", "note_culturale": null}', NULL),
    (1064, 'Litighiamo spesso, ma ci vogliamo bene.', 'phrase', 'd922ca2a1a833c2fbbe4dd410b64fb309d05c08e22062c40945841eed6171703', 'B1', false, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_008", "note_culturale": null}', NULL),
    (1065, 'Riitelemme usein, mutta välitämme toisistamme.', 'phrase', '201fbb3f7a61660f66ecb495e7c6468bf438d0e71a8501f26b5dbf7e5035b31d', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_008", "note_culturale": null}', NULL),
    (1066, 'We often argue, but we love each other.', 'phrase', '5ffec143c1d811492fccd70bc16b23f85a5e2914eee0d372d9d74b17007ebaab', 'B1', false, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_008", "note_culturale": null}', NULL),
    (1067, 'A casa mia si mangia sempre tutti insieme.', 'phrase', 'bc4554b426187c54e732a8684015ac2ce4b1436d7e4b7ec8ca87ac8e3c4e97c6', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_009", "note_culturale": null}', NULL),
    (1068, 'Meillä kotona syödään aina kaikki yhdessä.', 'phrase', '51d2b6dae356c4a7f432650dcbda6da35b05c5d5365114ba0976359c323d81d7', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_009", "note_culturale": null}', NULL),
    (1069, 'At my house, we always eat together.', 'phrase', '578772d0313029444a31580f57cad6c013058a50a4dab5b42de9493a5e42aa15', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_009", "note_culturale": null}', NULL),
    (1070, 'Non vedo l''ora di diventare zio!', 'phrase', 'b8fd0d9532d9cd8d20e5eb6104cdfafcaa9ba79266ae2f0b13bc4d1c400fcf9b', 'A1', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_010", "note_culturale": null}', NULL),
    (1071, 'En malta odottaa, että minusta tulee setä!', 'phrase', '9064a0287cbbecacedd5fa6e633e953a8d9a4fa677cdd4a15c7f5f834054e526', 'A1', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_010", "note_culturale": null}', NULL),
    (1072, 'I can''t wait to become an uncle!', 'phrase', 'c47da49144c85929f8b8f8387df004da131f3f484c9f507709d8c52d43d725be', 'A1', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_010", "note_culturale": null}', NULL),
    (1073, 'La convivenza è una prova per la coppia.', 'phrase', 'd2643277eff1959a8846a6d2e7451f65caa800d2d077787d8210e5ae387f5f09', 'B1', false, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_011", "note_culturale": null}', NULL),
    (1074, 'Yhdessä asuminen on koetus pariskunnalle.', 'phrase', '4928ca1080186c40e7458f2879ecac6065527d661beca1b9e969cf36e2648b4e', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_011", "note_culturale": null}', NULL),
    (1075, 'Living together is a test for the couple.', 'phrase', '4b3bdb48b7a0f9c6639f64767a2e5785f43c9a82fb0039729a9e528202689763', 'B1', false, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_011", "note_culturale": null}', NULL),
    (1076, 'I miei genitori mi hanno messo al mondo, ma non mi capiscono.', 'phrase', 'c558c2f8d72ba94ead4b7f202ec9a88cec93824c6b062ad99abf30c4d57aba71', 'B1', false, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_012", "note_culturale": null}', NULL),
    (1077, 'Vanhempani ovat synnyttäneet minut, mutta eivät ymmärrä minua.', 'phrase', '226656db222e4bdaa1568a9767bc70ad02246cc3be65dd9563cf97e402e6d201', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_012", "note_culturale": null}', NULL),
    (1078, 'My parents brought me into the world, but they don''t understand me.', 'phrase', 'f3b4f2b9d19d48553f5f96e00f9d0a50550d17de378dcd26485df82c705d1853', 'B1', false, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_012", "note_culturale": null}', NULL),
    (1079, 'Devo andare a trovare i miei nonni, è da tanto che non li vedo.', 'phrase', '1d8a0cdf54950bb1a87b4628d3cb1dc29763bd5217eb5c1b4769019bfb141e80', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_013", "note_culturale": null}', NULL),
    (1080, 'Minun täytyy mennä tapaamaan isovanhempiani, on pitkä aika siitä kun olen nähnyt heitä.', 'phrase', '0ca7003ba489c24d8feaf92a2124993b2c9c4a608342e1736fb7133e30a6030c', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_013", "note_culturale": null}', NULL),
    (1081, 'I have to go visit my grandparents, it''s been a long time since I''ve seen them.', 'phrase', '173a75a9d5433b8db07b722bd745f37681c606ca0c146741465ae0e8e8b45cc8', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_013", "note_culturale": null}', NULL),
    (1082, 'Siamo cresciuti insieme, siamo come fratelli.', 'phrase', 'a341709ca72c2e8b1674d1186027c1ca08805b68e5ae1c11b20c3c19e33989f6', 'A1', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_014", "note_culturale": null}', NULL),
    (1083, 'Olemme kasvaneet yhdessä, olemme kuin veljiä.', 'phrase', 'e985c964eb3e45bf79250877799c999f85be283953aa75d98a8677832f0a58c7', 'A1', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_014", "note_culturale": null}', NULL),
    (1084, 'We grew up together, we are like brothers.', 'phrase', '6bebd7a5ecb9781e1e36a5948358b67e127fdad1079420a063a8f245c6dfc42d', 'A1', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_014", "note_culturale": null}', NULL),
    (1085, 'Mia moglie è la mia roccia.', 'phrase', 'cceb1e3e5f8565d83e30da5ead95f426a49e88d1cdbf239ccd150074cb339a48', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_015", "note_culturale": "Metafora per indicare una persona di grande supporto."}', NULL),
    (1086, 'Vaimoni on minun kallioni.', 'phrase', 'c06bb9d69bceea1f95e80879f8a005ab9b37cdb07282aa3d7bfa54bc9ee9e2ca', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_015", "note_culturale": "Metafora per indicare una persona di grande supporto."}', NULL),
