    (1149, 'Olemme hyvin yhtenäinen perhe.', 'phrase', 'ab28b5f1f6246c71a89f42bd0005b16a82723753bf147c0280c4518b75537ab9', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_036", "note_culturale": null}', NULL),
    (1150, 'We are a very close-knit family.', 'phrase', '2b56be764feab824d5740e322685c884a7f3709c734567c86f9015a794961128', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_036", "note_culturale": null}', NULL),
    (1151, 'Devo andare a trovare i miei, mi mancano.', 'phrase', '474eaa57fe24154637ef34b2c600e5b10d3a60c975bb7af90c7169247d0fcd2e', 'A1', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_037", "note_culturale": null}', NULL),
